module mux_2to1_8bit(data_in_0, b, sel, y);

    input  [7:0] data_in_0;  
    input  [7:0] b;  
    input  sel;
    output  [7:0] y;
    reg   [7:0]  y;

    always @(*)
          begin
            if (sel)
                y = b;
            else
                y = data_in_0;
          end  

endmodule
